```matlab
% Generate a sample signal
t = linspace(0, 1, 1000);
x = sin(2*pi*30*t) + sin(2*pi*50*t) + sin(2*pi*80*t);

% Set parameters
ensembleSize = 100;       % Number of ensembles
maxIterations = 100;      % Maximum number of sifting iterations

% Perform CEEMDAN
imf = ceemdan(x, ensembleSize, maxIterations);

% Display the results
