subplot(length(imf)+1, 1, 1);
plot(t, x);
title('Original Signal');
xlabel('Time');
ylabel('Amplitude');

for i = 1:length(imf)
    subplot(length(imf)+1, 1, i+1);
    plot(t, imf(i, :));
    title(['IMF ', num2str(i)]);
    xlabel('Time');
    ylabel('Amplitude');
